const item = $input.first() || {};
const json = item.json || {};
const body = json.body && typeof json.body === 'object' ? json.body : json;

const objectValue = (value) => value && typeof value === 'object' && !Array.isArray(value) ? value : undefined;
const firstObjectValue = (value) => Array.isArray(value)
  ? value.find((entry) => entry && typeof entry === 'object' && !Array.isArray(entry))
  : objectValue(value);
const stringValue = (value) => typeof value === 'string' || typeof value === 'number' ? String(value).trim() : '';
const numberValue = (value) => {
  const parsed = typeof value === 'number' ? value : Number.parseInt(stringValue(value), 10);
  return Number.isFinite(parsed) && parsed >= 0 ? parsed : 0;
};
const base64Value = (value) => {
  const raw = stringValue(value);
  const marker = ';base64,';
  const markerIndex = raw.indexOf(marker);
  return markerIndex >= 0 ? raw.slice(markerIndex + marker.length).trim() : raw;
};

const data = firstObjectValue(body.data) || body;
const event = stringValue(body.event || body.eventType || body.type || data.event || data.eventType || data.type)
  .toUpperCase()
  .replace(/[.-]/g, '_');
if (event && event !== 'MESSAGES_UPSERT') {
  return [{ json: { skip: true, reason: `unsupported_event:${event}` } }];
}

const key = objectValue(data.key) || {};
const rawMessage = objectValue(data.message) || objectValue(body.message) || {};
const innerMsg = objectValue(objectValue(rawMessage.ephemeralMessage)?.message)
  || objectValue(objectValue(rawMessage.viewOnceMessage)?.message)
  || objectValue(objectValue(rawMessage.viewOnceMessageV2)?.message)
  || objectValue(objectValue(rawMessage.documentWithCaptionMessage)?.message)
  || rawMessage;

const remoteJid = stringValue(key.remoteJid || data.remoteJid || data.chatId || body.remoteJid || body.chatId);
if (!remoteJid.endsWith('@g.us')) return [{ json: { skip: true, reason: 'not_group' } }];

const mediaTypes = [
  { key: 'imageMessage', type: 'image', fallbackMimeType: 'image/jpeg' },
  { key: 'documentMessage', type: 'document', fallbackMimeType: 'application/octet-stream' },
  { key: 'audioMessage', type: 'audio', fallbackMimeType: 'audio/ogg' },
  { key: 'videoMessage', type: 'video', fallbackMimeType: 'video/mp4' },
  { key: 'stickerMessage', type: 'sticker', fallbackMimeType: 'image/webp' }
];
let mediaType = '';
let mediaData = undefined;
let mediaFileName = '';
let mediaMimeType = '';
let mediaFileSize = 0;
for (const mt of mediaTypes) {
  const candidate = objectValue(innerMsg[mt.key]);
  if (!candidate) continue;
  mediaType = mt.type;
  mediaData = candidate;
  mediaFileName = stringValue(candidate.fileName || candidate.title || `attachment.${mt.type}`);
  mediaMimeType = stringValue(candidate.mimetype || candidate.mimeType) || mt.fallbackMimeType;
  mediaFileSize = numberValue(candidate.fileLength || candidate.fileSize || candidate.sizeBytes);
  break;
}

const inlineMedia = objectValue(body.media) || objectValue(data.media) || mediaData || {};
const inlineBase64 = base64Value(
  body.media_data_b64
    || body.mediaDataBase64
    || body.dataBase64
    || body.base64
    || data.media_data_b64
    || data.mediaDataBase64
    || data.dataBase64
    || data.base64
    || inlineMedia.dataBase64
    || inlineMedia.base64
);
const messageText = stringValue(
  mediaData?.caption
    || innerMsg.conversation
    || objectValue(innerMsg.extendedTextMessage)?.text
    || data.text
    || data.body
    || body.text
    || body.body
);
if (!messageText && !mediaType) return [{ json: { skip: true, reason: 'empty' } }];
const prefixPattern = /^\/kb(?:\s+|$)/i;
if (!prefixPattern.test(messageText)) return [{ json: { skip: true, reason: 'group_missing_prefix' } }];
const invokedMessageText = messageText.replace(prefixPattern, '').trim();
return [{ json: {
  skip: false,
  message_text: invokedMessageText || (mediaType ? `[${mediaType}: ${mediaFileName}]` : ''),
  sender_jid: stringValue(key.participant || data.participant || body.participant || remoteJid),
  group_jid: remoteJid,
  message_id: stringValue(key.id || data.messageId || body.messageId),
  has_media: Boolean(mediaType),
  media_type: mediaType,
  media_file_name: mediaFileName,
  media_mime_type: mediaMimeType,
  media_file_size: mediaFileSize,
  media_data_b64: inlineBase64,
  raw_message: JSON.stringify(data),
} }];

const base = $node['Has Media?'].json || {};
const objectValue = (value) => value && typeof value === 'object' && !Array.isArray(value) ? value : undefined;
const stringValue = (value) => typeof value === 'string' || typeof value === 'number' ? String(value).trim() : '';
const base64Value = (value) => {
  const raw = stringValue(value);
  const marker = ';base64,';
  const markerIndex = raw.indexOf(marker);
  return markerIndex >= 0 ? raw.slice(markerIndex + marker.length).trim() : raw;
};
const data = objectValue($json.data);
const response = objectValue($json.response);
const downloadedBase64 = base64Value(
  $json.base64
    || $json.dataBase64
    || $json.media_data_b64
    || data?.base64
    || data?.dataBase64
    || data?.media_data_b64
    || response?.base64
    || response?.dataBase64
    || response?.media_data_b64
);
return [{ json: { ...base, media_data_b64: downloadedBase64 || String(base.media_data_b64 || '').trim() } }];

const item = $input.first() || {};
const json = item.json || {};
const payload = {
  externalIdentity: {
    provider: 'whatsapp',
    identityType: 'jid',
    externalId: String(json.group_jid || '').trim(),
  },
  payload: {
    messageText: String(json.message_text || '').trim(),
    senderId: String(json.sender_jid || '').trim(),
    groupId: String(json.group_jid || '').trim(),
    messageId: String(json.message_id || '').trim(),
    hasMedia: Boolean(json.has_media),
    media: {
      fileName: String(json.media_file_name || '').trim(),
      mimeType: String(json.media_mime_type || 'application/octet-stream').trim(),
      sizeBytes: Number(json.media_file_size || 0),
      dataBase64: String(json.media_data_b64 || '').trim(),
    },
  },
  group_jid: String(json.group_jid || '').trim(),
};
return [{ json: payload }];

const input = $node['Prepare Conversation Input']?.json || {};
const result = $json && typeof $json === 'object' ? $json : {};
const nested = result.conversationResult && typeof result.conversationResult === 'object' ? result.conversationResult : {};
const action = String(result.action || nested.action || '').trim();
const replyText = String(result.replyText || nested.replyText || '').trim();
const confirmText = String(result.confirmText || replyText || '').trim();
return [{ json: { ...result, action, group_jid: String(input.group_jid || result.groupId || '').trim(), replyText, confirmText } }];

const item = $input.first() || {};
const json = item.json || {};
const body = json.body && typeof json.body === 'object' ? json.body : json;
const payload = body.payload && typeof body.payload === 'object' ? body.payload : body;
return [{ json: { ...payload, payload } }];
